def rgbHueToBinary(r, g, b):
    # Calculate the hue based on the RGB values using the HSV formula
    h = ((max(max(r, g), b) - min(min(r, g), b)) / 255) * 6

    # Determine which of the six hues this value falls into
    if h < (1/6):
        return '01'
    elif h < (2/6):
        return '10'
    elif h < (3/6):
        return '11'
    elif h < (4/6):
        return '00'
    elif h < (5/6):
        return '01'
    else:
        return '10'

